// Stage 1: Apify discovery — hashtag posts → profile scraping → raw_prospects
// Dinámico por niche: solo descubre en los niches que tienen al menos un closer activo,
// y etiqueta cada prospecto con el niche exacto en el que se encontró (sin ambigüedad).

const axios = require('axios');
async function fetch(url, opts) {
  opts = opts || {};
  const r = await axios({ method: opts.method || 'GET', url, headers: opts.headers || {}, data: opts.body, validateStatus: () => true, responseType: 'text', transformResponse: [x => x] });
  const text = r.data || '';
  return { ok: r.status >= 200 && r.status < 300, status: r.status, text: () => Promise.resolve(text), json: () => Promise.resolve(JSON.parse(text)) };
}

const APIFY_TOKEN = $env.APIFY_TOKEN;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet ${path}: ${await r.text()}`);
  return r.json();
}

const sleep = ms => new Promise(r => setTimeout(r, ms));

async function apifyRunAndWait(actorSlug, input, maxWaitMs = 240000) {
  const start = await fetch(
    `https://api.apify.com/v2/acts/${actorSlug}/runs?token=${APIFY_TOKEN}`,
    { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(input) }
  );
  const startData = await start.json();
  if (!startData?.data?.id) throw new Error('Apify start failed: ' + JSON.stringify(startData));

  const runId = startData.data.id;
  const datasetId = startData.data.defaultDatasetId;
  const deadline = Date.now() + maxWaitMs;

  while (Date.now() < deadline) {
    await sleep(6000);
    const info = await (await fetch(`https://api.apify.com/v2/actor-runs/${runId}?token=${APIFY_TOKEN}`)).json();
    const status = info.data?.status;
    if (status === 'SUCCEEDED') break;
    if (status === 'FAILED' || status === 'ABORTED') throw new Error(`Apify run ${status} — runId: ${runId}`);
  }

  const items = await (await fetch(`https://api.apify.com/v2/datasets/${datasetId}/items?token=${APIFY_TOKEN}&limit=200`)).json();
  return Array.isArray(items) ? items : [];
}

async function supabaseUpsert(table, rows) {
  if (!rows.length) return [];
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=source,source_id`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation,resolution=ignore-duplicates' },
    body: JSON.stringify(rows),
  });
  if (!res.ok) throw new Error(`Supabase upsert ${table}: ${await res.text()}`);
  return res.json();
}

// Hashtags por niche fusionado — 22 niches (de los 50 originales), cobertura del onboarding actual
const NICHE_HASHTAGS = {
  // Desarrollo
  'mentalidad-liderazgo': ['altorendimiento', 'mentalidadabundancia', 'liderazgo', 'inteligenciaemocional', 'coachingejecutivo', 'leydeatraccion'],
  'productividad-oratoria': ['productividad', 'oratoria', 'gestiondeltiempo', 'hablarenpublico', 'habitossaludables', 'comunicacionefectiva'],
  // Espiritualidad
  'coaching-espiritual': ['humandesign', 'astrologia', 'mentoriaespiritual', 'coachingtransformacional', 'cartaastral', 'despertarfemenino'],
  // Finanzas
  'trading-bolsa': ['trading', 'bolsa', 'tradingforex', 'valueinvesting', 'inversiones', 'inversionenbolsa'],
  'inversion-inmobiliaria': ['inversioninmobiliaria', 'realestate', 'mentoriainmobiliaria', 'bienesraices', 'inversioninternacional', 'agenteinmobiliario'],
  'finanzas-alternativas': ['libertadfinanciera', 'criptomonedas', 'inversionangel', 'educacionfinanciera', 'web3', 'startups'],
  // IA
  'ia-aplicada': ['ianegocios', 'agenciadeia', 'promptengineering', 'automatizaciones', 'infoproductor', 'agentesdeia'],
  // Marketing
  'funnels-copywriting': ['embudosdeventa', 'copywriting', 'funnels', 'redaccionpublicitaria', 'marketingdigital', 'copywriter'],
  'trafico-pagado-seo': ['metaads', 'seo', 'publicidadfacebook', 'seoconia', 'anunciosfacebook', 'posicionamientoweb'],
  'contenido-organico': ['crecimientoorganico', 'ugccreator', 'youtuber', 'emailmarketing', 'tiktokgrowth', 'contentcreator'],
  // Negocios
  'ecommerce-saas': ['ecommerce', 'microsaas', 'amazonfba', 'dropshipping', 'indiehacker', 'privatelabel'],
  'agencias-consultoria-b2b': ['consultoriab2b', 'agenciamarketing', 'serviciosproductizados', 'consultorianegocios', 'agenciadigital', 'naas'],
  'closers-lanzamientos': ['closerdeventas', 'lanzamientodigital', 'formacioncloser', 'lanzamientoonline', 'ventashightickets', 'plflaunch'],
  'compra-venta-lifestyle': ['compraventadenegocios', 'lifestylebusiness', 'adquisiciondenegocios', 'negociodigital', 'comprarunempresa', 'libertadgeografica'],
  // Relaciones
  'relaciones-bienestar': ['coachingdemujeres', 'terapiadepareja', 'empoderamientofemenino', 'sexualidadconsciente', 'autoestimamujer', 'relacionessanas'],
  'seduccion-masculina': ['seduccion', 'atraccionmasculina', 'hombresalfa', 'seductormasculino', 'desarrollomasculino'],
  // Salud
  'fitness-composicion': ['perdidadepeso', 'hipertrofia', 'bajardepeso', 'culturismo', 'transformacionfisica', 'ganarmusculo'],
  'longevidad-biohacking': ['longevidad', 'biohacking', 'antiaging', 'saludhormonal', 'saludylongevidad', 'optimizacionhormonal'],
  'salud-mental': ['saludmental', 'ansiedad', 'burnout', 'bienestarmental', 'psicologiapositiva'],
  // Skills
  'coaches-cobrar-mas': ['coachesquecobranmas', 'preciosaltos', 'hightickets', 'coachingrentable', 'cobrarmasporloqueeres'],
  'musica-produccion': ['produccionmusical', 'musicaproduccion', 'beatmaker', 'productormusical', 'estudiodegrabacion'],
  'coaching-ejecutivo-c-level': ['coachingejecutivo', 'clevelcoaching', 'liderazgoejecutivo', 'coachexecutivo', 'altadireccion'],
};

// ── Determinar qué niches necesitan discovery hoy (closers activos) ────────────
const activeClosers = await sbGet(`closers?status=eq.active&select=id,selected_niches`);
const neededNicheIdSet = new Set();
for (const c of activeClosers) {
  (c.selected_niches || []).forEach(id => neededNicheIdSet.add(id));
}

if (neededNicheIdSet.size === 0) {
  console.log('Sin closers activos con niches seleccionados — nada que descubrir');
  return [{ json: { discovered: 0, note: 'sin niches activos' } }];
}

const allNiches = await sbGet(`niches?select=id,slug`);
const nicheSlugById = new Map(allNiches.map(n => [n.id, n.slug]));

// ── Control de coste: solo se descubre en niches con poco inventario disponible ────────────
// Discovery es lo más caro en Apify. Si un niche ya tiene suficientes prospectos cualificados
// sin usar (no asignados aún a ningún closer), no hace falta gastar más en buscar — se reutiliza
// el inventario acumulado de días anteriores. Esto evita rastrear los 10 niches todos los días
// cuando solo unos pocos realmente lo necesitan.
const MIN_BUFFER_PER_NICHE = 25;
const cutoff30dBuffer = new Date(Date.now() - 30 * 86400000).toISOString();
const [allQualified, recentAssignmentsBuffer] = await Promise.all([
  sbGet(`qualified_prospects?select=id,detected_niche_id`),
  sbGet(`lead_assignments?assigned_at=gte.${cutoff30dBuffer}&select=prospect_id`),
]);
const assignedSetBuffer = new Set(recentAssignmentsBuffer.map(a => a.prospect_id));
const bufferByNicheId = new Map();
for (const q of allQualified) {
  if (assignedSetBuffer.has(q.id)) continue; // ya usado, no cuenta como inventario disponible
  bufferByNicheId.set(q.detected_niche_id, (bufferByNicheId.get(q.detected_niche_id) || 0) + 1);
}

const allActiveSlugs = [...neededNicheIdSet].map(id => nicheSlugById.get(id)).filter(Boolean);
const activeSlugs = [...neededNicheIdSet]
  .filter(id => {
    const buffer = bufferByNicheId.get(id) || 0;
    const slug = nicheSlugById.get(id) || id;
    if (buffer >= MIN_BUFFER_PER_NICHE) {
      console.log(`  [${slug}] buffer suficiente (${buffer} disponibles) — se omite discovery hoy, ahorro de coste`);
      return false;
    }
    return true;
  })
  .map(id => nicheSlugById.get(id))
  .filter(Boolean);

console.log(`Niches totales activos: ${allActiveSlugs.length} — necesitan discovery hoy: ${activeSlugs.length} (${activeSlugs.join(', ') || 'ninguno'})`);

if (activeSlugs.length === 0) {
  console.log('Todos los niches activos tienen buffer suficiente — discovery omitido por completo hoy');
  return [{ json: { discovered: 0, note: 'buffer suficiente en todos los niches', niches_con_buffer: allActiveSlugs } }];
}

// ── Por cada niche activo: hashtag scraping independiente (sin ambigüedad de origen) ──
// Se procesan en lotes en paralelo (no secuencial) para no acumular tiempo de ejecución
// del nodo — con muchos niches activos, hacerlo uno a uno supera el timeout del Task Runner de n8n.
const usernameToNiche = new Map(); // username -> primer niche donde se encontró

// Volumen recortado para controlar coste de Apify: con pocos closers, el coste de rastrear
// muchos niches se reparte entre poca gente. Recorte moderado (no agresivo) para no arriesgar
// la garantía de 5 leads/día — si el % de cualificación es bajo, menos volumen de entrada puede
// dejar a un niche por debajo de su cuota. El ahorro principal viene del buffer-skip (arriba).
const HASHTAGS_PER_NICHE = 4;
const RESULTS_LIMIT_PER_HASHTAG_BATCH = 30;
const USERNAMES_PER_NICHE = 25;

async function discoverNiche(slug) {
  const hashtags = (NICHE_HASHTAGS[slug] || []).slice(0, HASHTAGS_PER_NICHE);
  if (!hashtags.length) {
    console.log(`  [${slug}] sin hashtags mapeados — omitido`);
    return [];
  }
  const directUrls = hashtags.map(h => `https://www.instagram.com/explore/tags/${h}/`);
  console.log(`  [${slug}] discovery con hashtags: ${hashtags.join(', ')}`);
  try {
    const posts = await apifyRunAndWait('apify~instagram-scraper', {
      directUrls,
      resultsType: 'posts',
      resultsLimit: RESULTS_LIMIT_PER_HASHTAG_BATCH,
    }, 120000);

    const cutoff = Date.now() - 72 * 3600 * 1000;
    const recentPosts = posts.filter(p => p.timestamp && new Date(p.timestamp).getTime() > cutoff);
    const usernames = [...new Set(recentPosts.map(p => p.ownerUsername).filter(Boolean))].slice(0, USERNAMES_PER_NICHE);
    console.log(`  [${slug}] posts recientes: ${recentPosts.length} — usernames: ${usernames.length}`);
    return usernames;
  } catch (e) {
    console.log(`  [${slug}] discovery falló (no bloqueante): ${e.message}`);
    return [];
  }
}

const NICHE_CONCURRENCY = 8; // niches procesados a la vez — equilibrio entre velocidad y límites de Apify
for (let i = 0; i < activeSlugs.length; i += NICHE_CONCURRENCY) {
  const batch = activeSlugs.slice(i, i + NICHE_CONCURRENCY);
  const results = await Promise.all(batch.map(slug => discoverNiche(slug).then(usernames => ({ slug, usernames }))));
  for (const { slug, usernames } of results) {
    for (const u of usernames) {
      if (!usernameToNiche.has(u)) usernameToNiche.set(u, slug);
    }
  }
}

const rawUsernames = [...usernameToNiche.keys()];
console.log(`Usernames únicos encontrados: ${rawUsernames.length}`);

if (!rawUsernames.length) return [{ json: { discovered: 0, note: 'sin usernames' } }];

// ── Evitar re-scrapear perfiles que ya tenemos frescos — ahorro directo de Apify ────────
// Si un username se repite en hashtags de varios días (común), no hace falta pagar otra vez
// por su perfil si ya lo tenemos de los últimos 5 días.
const cutoff5dProfiles = new Date(Date.now() - 5 * 86400000).toISOString();
const recentlyScraped = await sbGet(`raw_prospects?source=eq.instagram&discovered_at=gte.${cutoff5dProfiles}&select=handle`);
const recentlyScrapedSet = new Set(recentlyScraped.map(r => r.handle));
const allUsernames = rawUsernames.filter(u => !recentlyScrapedSet.has(u));
const skipped = rawUsernames.length - allUsernames.length;
if (skipped > 0) console.log(`Perfiles omitidos por ya estar frescos (<5 días): ${skipped}`);

if (!allUsernames.length) return [{ json: { discovered: 0, note: 'todos los perfiles ya estaban frescos' } }];

// ── Profile scraping combinado — un solo apify call para todos los niches ──────
console.log('Scrapeando perfiles...');
const profiles = await apifyRunAndWait('apify~instagram-profile-scraper', { usernames: allUsernames }, 300000);
console.log(`Perfiles recibidos: ${profiles.length}`);

// ── Guardar raw_prospects con el niche de origen incluido ───────────────────────
const rows = profiles
  .filter(p => p.username)
  .map(p => ({
    source: 'instagram',
    source_id: p.username,
    handle: p.username,
    url: `https://www.instagram.com/${p.username}/`,
    raw_data: { ...p, __niche_slug: usernameToNiche.get(p.username) || null },
  }));

await supabaseUpsert('raw_prospects', rows);
console.log(`raw_prospects upserted: ${rows.length}`);

return [{ json: { discovered: rows.length, niches: activeSlugs } }];

// Stage 2: Enriquecimiento y filtro duro
// Filtros: followers 5K-100K, externalUrl presente, biography en español
// Lee raw_prospects de las últimas 2h y guarda en qualified_prospects.

const axios = require('axios');
async function fetch(url, opts) {
  opts = opts || {};
  const r = await axios({ method: opts.method || 'GET', url, headers: opts.headers || {}, data: opts.body, validateStatus: () => true, responseType: 'text', transformResponse: [x => x] });
  const text = r.data || '';
  return { ok: r.status >= 200 && r.status < 300, status: r.status, text: () => Promise.resolve(text), json: () => Promise.resolve(JSON.parse(text)) };
}

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet ${path}: ${await r.text()}`);
  return r.json();
}

async function sbInsert(table, rows) {
  if (!rows.length) return [];
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation,resolution=ignore-duplicates' },
    body: JSON.stringify(rows),
  });
  if (!r.ok) throw new Error(`sbInsert ${table}: ${await r.text()}`);
  return r.json();
}

function detectRegion(profile) {
  // Padding con espacios al inicio/fin para que las señales con espacio de margen
  // también cacen al principio o final del texto concatenado.
  const text = (' ' + [
    profile.biography || '',
    profile.externalUrl || '',
    profile.location || '',
    profile.city || '',
    profile.country || '',
  ].join(' ') + ' ').toLowerCase();

  const spainSigns = [
    'españa', 'spain', 'madrid', 'barcelona', 'valencia', 'sevilla', 'bilbao',
    'zaragoza', 'málaga', 'alicante', 'murcia', 'galicia', 'asturias', 'canarias',
    '.es/', '+34', 'wa.me/34', '🇪🇸',
    // Modismos / vocabulario característico del español de España
    ' vosotros', ' vosotras', ' currar', ' curro ', ' tío ', ' tía ', ' flipa',
    ' mola ', ' chaval', ' móvil ', ' guay ',
  ];
  const latamSigns = [
    'mexico', 'méxico', 'colombia', 'argentina', 'peru', 'perú', 'chile',
    'venezuela', 'ecuador', 'bolivia', 'uruguay', 'paraguay', 'costa rica',
    'bogotá', 'medellín', 'cali', 'buenos aires', 'lima', 'santiago',
    'monterrey', 'guadalajara', 'cdmx', 'caracas', 'guayaquil', 'quito',
    '.mx/', '.co/', '.ar/', '.pe/', '.cl/', '.ve/', '.ec/', '.bo/', '.uy/',
    '+52', '+54', '+57', '+51', '+56', '+58',
    'wa.me/52', 'wa.me/54', 'wa.me/57', 'wa.me/51', 'wa.me/56', 'wa.me/58',
    '🇲🇽', '🇨🇴', '🇦🇷', '🇵🇪', '🇨🇱',
    // Modismos / vocabulario característico del español latinoamericano
    ' ustedes', ' platicar', ' chevere', ' celular', ' carro ', ' plata ',
    ' chido', ' bacán', ' parce', ' pana ',
  ];

  const spainCount = spainSigns.filter(s => text.includes(s)).length;
  const latamCount = latamSigns.filter(s => text.includes(s)).length;
  if (spainCount > 0 && spainCount >= latamCount) return 'spain';
  if (latamCount > 0) return 'latam';
  return 'unknown';
}

// Señales que identifican portugués — 'ção' solo ya caza el 90% de bios PT
const PT_HINTS = [
  'ção', 'ções', 'ção!', // sufijo exclusivo del portugués
  'você', 'voce ', 'nosso', 'nossa', 'nossas', 'nossos',
  'empreend', 'dinheiro', 'trabalho', 'fazendo', 'obrigad',
  'conteúdo', 'negócio', 'solução', 'criação', 'conexão',
  'sou ', 'meu ', 'minha', 'ajudo ', 'ajudar', 'aprenda ',
  'somos um', 'somos uma', 'criador de', 'inovação', 'ajudamos',
];

// Lista de inglés ampliada — la anterior solo cazaba frases de marketing concretas.
// Se añaden palabras función muy comunes en cualquier frase en inglés (con espacios de margen
// para evitar falsos positivos dentro de palabras en español).
const EN_HINTS = [
  'i am ', 'i help ', 'i teach', 'follow me', 'dm for', 'i show', 'i share',
  'building', 'founder & ceo', 'speaker &', 'coach for', 'helping you',
  ' the ', ' and ', ' with ', ' your ', ' you ', ' for ', ' this ', ' that ',
  ' from ', ' have ', " i'm ", " i've ", " don't ", " can't ", ' our ', ' are ',
  ' will ', ' just ', ' more ', ' than ', ' here ', ' there ', " let's ",
  'link in bio', 'click here', 'sign up', 'learn more', 'find out', 'check out',
  'book a call', 'book your', 'schedule a call', 'message me', 'reach out',
];

// Red de seguridad general: si el texto es razonablemente largo y no tiene NINGUNA señal
// positiva de español (palabras comunes, tildes, ñ), es sospechoso aunque no coincida con
// ningún idioma específico de la lista — cubre alemán, italiano, etc. sin necesidad de
// mantener una lista negra por cada idioma posible.
const SPANISH_POSITIVE_HINTS = [
  ' de ', ' que ', ' para ', ' con ', ' los ', ' las ', ' una ', ' esta ',
  ' soy ', ' mi ', ' tu ', ' te ', ' por ', ' del ', ' como ', ' más ',
  ' su ', ' sus ', ' al ', ' es ', 'ción', 'mente ', 'ando ', 'iendo ',
];

// Lista de palabras francesas ampliada — la anterior (3 frases) dejaba pasar bios en francés
const FR_HINTS = [
  'je suis', 'je vous', 'pour vous', 'nous sommes', 'mon métier', "je t'aide",
  'je vous aide', 'avec moi', "aujourd'hui", 'votre vie', 'notre équipe',
  'coach pour', 'entraîneur', 'formation en ligne', 'voici comment', 'suivez-moi',
  'abonnez-vous', 'rejoignez', 'cliquez ici', 'lien dans la bio', 'découvrez',
  'gratuitement', "c'est", "n'hésite", 'merci de', 'bonjour à', 'depuis que',
  'mes formations', 'mon programme', 'ma méthode', 'entrepreneure', 'créatrice de',
  'coach business', 'développement personnel',
];

// Caracteres exclusivos del francés (nunca aparecen en español) — detecta bios en francés
// aunque no usen ninguna de las frases de arriba. Señal mucho más fiable que el listado de palabras.
const FR_CHAR_PATTERN = /[àâèêëîïôûùÿœ]/;

// Caracteres exclusivos del portugués (nasal ã/õ, nunca en español) — refuerzo del filtro PT
const PT_CHAR_PATTERN = /[ãõ]/;

// Bios que indican que el infoproductor no es accesible directamente (tiene equipo/asistente)
const INACCESSIBLE_HINTS = [
  'escríbele a mi', 'escríbenos a', 'habla con mi asistente', 'habla con mi equipo',
  'dm a mi equipo', 'contacta con mi equipo', 'mensajea a mi equipo',
  'escribe a mi equipo', 'escribe a mi asistente', 'contacta a mi equipo',
  'habla con nuestro equipo', 'escribe a nuestro equipo',
];

function looksSpanish(bio) {
  if (!bio) return true;
  // Padding con espacios para que las señales con margen también cacen al inicio/fin del texto.
  const b = ' ' + bio.toLowerCase() + ' ';
  if (FR_CHAR_PATTERN.test(b)) return false;
  if (PT_CHAR_PATTERN.test(b)) return false;
  if (PT_HINTS.some(h => b.includes(h))) return false;
  if (EN_HINTS.some(h => b.includes(h))) return false;
  if (FR_HINTS.some(h => b.includes(h))) return false;

  // Red de seguridad general: texto razonablemente largo sin ninguna señal positiva de
  // español es sospechoso, sea cual sea el idioma exacto (alemán, italiano, etc.)
  if (b.trim().length >= 20) {
    const hasSpanishSignal = SPANISH_POSITIVE_HINTS.some(h => b.includes(h)) || /[áéíóúñ]/.test(b);
    if (!hasSpanishSignal) return false;
  }

  return true;
}

// Mapa slug → id para resolver el niche que discovery ya etiquetó en cada prospect
const allNiches = await sbGet(`niches?select=id,slug`);
const nicheIdBySlug = new Map(allNiches.map(n => [n.slug, n.id]));

// Leer raw_prospects de las últimas 3h sin qualified correspondiente
const cutoff = new Date(Date.now() - 3 * 3600 * 1000).toISOString();
const rawProspects = await sbGet(
  `raw_prospects?source=eq.instagram&discovered_at=gte.${cutoff}&select=id,handle,raw_data`
);
console.log(`raw_prospects a evaluar: ${rawProspects.length}`);

const qualified = [];

for (const rp of rawProspects) {
  const p = rp.raw_data;
  const followers = p.followersCount || 0;
  const hasLanding = !!p.externalUrl;
  const spanishBio = looksSpanish(p.biography);

  // Filtros duros: followers, landing, idioma
  // 10K mínimo: autoridad suficiente para high ticket, max 100K para acceso directo al infoproductor
  if (followers < 10000 || followers > 100000) continue;
  if (!hasLanding) continue;
  if (!spanishBio) continue;
  // Filtrar cuentas donde el infoproductor no es accesible directamente
  if (INACCESSIBLE_HINTS.some(h => (p.biography || '').toLowerCase().includes(h))) continue;
  // Engagement rate: descartar audiencia muerta (< 0.5% likes/seguidores)
  // Usamos avgLikes si existe; si no hay dato, dejamos pasar (no penalizamos por ausencia de info)
  const avgLikes = p.avgLikes || p.likesCount || 0;
  if (avgLikes > 0 && followers > 0 && (avgLikes / followers) < 0.005) continue;

  // Niche de origen: lo etiquetó discovery según el hashtag donde se encontró el perfil
  const nicheId = nicheIdBySlug.get(p.__niche_slug);
  if (!nicheId) {
    console.log(`  @${rp.handle}: niche '${p.__niche_slug}' no resuelto — omitido`);
    continue;
  }

  qualified.push({
    raw_prospect_id: rp.id,
    handle: rp.handle,
    platform_links: {
      instagram: `https://www.instagram.com/${rp.handle}/`,
      landing: p.externalUrl,
      region: detectRegion(p),
    },
    followers,
    ads_count: 0,      // Se completará en sprint 2 con Meta Ads
    language: 'es',
    detected_niche_id: nicheId,
    detected_mode: 'both',
  });
}

console.log(`Calificados: ${qualified.length} de ${rawProspects.length}`);
await sbInsert('qualified_prospects', qualified);

return [{ json: { qualified: qualified.length, evaluated: rawProspects.length } }];

// Stage 3: Análisis profundo con Claude (§8.1 funnel + §8.3 value_opportunities)
// Solo procesa prospectos sin análisis o con análisis >7 días.
// Guarda en prospect_analyses.

const axios = require('axios');
async function fetch(url, opts) {
  opts = opts || {};
  const r = await axios({ method: opts.method || 'GET', url, headers: opts.headers || {}, data: opts.body, validateStatus: () => true, responseType: 'text', transformResponse: [x => x] });
  const text = r.data || '';
  return { ok: r.status >= 200 && r.status < 300, status: r.status, text: () => Promise.resolve(text), json: () => Promise.resolve(JSON.parse(text)) };
}

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;
const APIFY_TOKEN = $env.APIFY_TOKEN;
const META_ADS_TOKEN = $env.META_ADS_TOKEN || null;

const sleep = ms => new Promise(r => setTimeout(r, ms));

async function apifyRunAndWait(actorSlug, input, maxWaitMs = 180000) {
  const start = await fetch(
    `https://api.apify.com/v2/acts/${actorSlug}/runs?token=${APIFY_TOKEN}`,
    { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(input) }
  );
  const startData = await start.json();
  if (!startData?.data?.id) throw new Error('Apify start: ' + JSON.stringify(startData));
  const runId = startData.data.id;
  const datasetId = startData.data.defaultDatasetId;
  const deadline = Date.now() + maxWaitMs;
  while (Date.now() < deadline) {
    await sleep(6000);
    const info = await (await fetch(`https://api.apify.com/v2/actor-runs/${runId}?token=${APIFY_TOKEN}`)).json();
    const status = info.data?.status;
    if (status === 'SUCCEEDED') break;
    if (status === 'FAILED' || status === 'ABORTED') throw new Error(`Apify run ${status}`);
  }
  const items = await (await fetch(`https://api.apify.com/v2/datasets/${datasetId}/items?token=${APIFY_TOKEN}&limit=500`)).json();
  return Array.isArray(items) ? items : [];
}

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet: ${await r.text()}`);
  return r.json();
}

async function sbUpsert(table, rows, conflict) {
  if (!rows.length) return [];
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=${conflict}`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation,resolution=merge-duplicates' },
    body: JSON.stringify(rows),
  });
  if (!r.ok) throw new Error(`sbUpsert ${table}: ${await r.text()}`);
  return r.json();
}

async function claude(prompt, maxTokens = 1024, retries = 2) {
  let lastErr;
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const r = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': ANTHROPIC_KEY,
          'anthropic-version': '2023-06-01',
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-6',
          max_tokens: maxTokens,
          messages: [{ role: 'user', content: prompt }],
        }),
      });
      if (!r.ok) throw new Error(`Claude: ${await r.text()}`);
      return await parseClaudeResponse(r);
    } catch (e) {
      lastErr = e;
      if (attempt < retries) { console.log(`  Claude reintento ${attempt + 1}/${retries}: ${e.message}`); await sleep(2000 * (attempt + 1)); }
    }
  }
  throw lastErr;
}

async function parseClaudeResponse(r) {
  const data = await r.json();
  const raw = data.content[0].text.trim();
  // Strip ALL markdown code fences
  const noFences = raw.replace(/```(?:json)?\s*/gi, '').replace(/```/g, '').trim();
  try { return JSON.parse(noFences); } catch {}
  // Fallback: find first balanced JSON array/object (string-aware bracket tracking)
  for (let i = 0; i < noFences.length; i++) {
    if (noFences[i] !== '[' && noFences[i] !== '{') continue;
    const open = noFences[i], close = open === '[' ? ']' : '}';
    let depth = 1, j = i + 1, inStr = false, esc = false;
    while (j < noFences.length && depth > 0) {
      const c = noFences[j];
      if (esc) { esc = false; }
      else if (inStr) { if (c === '\\') esc = true; else if (c === '"') inStr = false; }
      else if (c === '"') inStr = true;
      else if (c === '[' || c === '{') depth++;
      else if (c === ']' || c === '}') depth--;
      j++;
    }
    if (depth === 0) { try { return JSON.parse(noFences.slice(i, j)); } catch {} }
  }
  return { raw };
}

async function queryMetaAds(handle) {
  if (!META_ADS_TOKEN) return [];
  try {
    const countries = encodeURIComponent(JSON.stringify(['ES','MX','CO','AR','CL','PE','VE','EC','BO','UY','CR','PA','CU','DO']));
    const fields = 'ad_creative_bodies,ad_creative_link_titles,page_name';
    const url = `https://graph.facebook.com/v21.0/ads_archive?search_terms=${encodeURIComponent(handle)}&ad_type=ALL&ad_reached_countries=${countries}&fields=${fields}&limit=10&access_token=${META_ADS_TOKEN}`;
    const r = await fetch(url);
    if (!r.ok) return [];
    const data = await r.json();
    return (data.data || []).slice(0, 8);
  } catch { return []; }
}

async function scrapeApifyTikTok(handle, maxItems = 5) {
  try {
    const profileUrl = `https://www.tiktok.com/@${handle}`;
    const items = await apifyRunAndWait('clockworks/free-tiktok-scraper', {
      profiles: [profileUrl],
      resultsPerPage: maxItems,
    }, 90000);
    return items.slice(0, maxItems).map(v => ({
      caption: (v.text || v.description || '').slice(0, 400),
      likes: v.diggCount || v.likes || 0,
      views: v.playCount || v.views || 0,
      type: 'Video',
      date: v.createTime ? new Date(v.createTime * 1000).toISOString().split('T')[0] : null,
    }));
  } catch (e) {
    console.log(`  TikTok scrape failed for @${handle}: ${e.message}`);
    return [];
  }
}

async function fetchLandingText(url, retries = 1) {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      // Timeout real vía axios (el AbortController anterior nunca se conectaba a la petición —
      // no hacía nada, las peticiones lentas podían colgarse sin límite).
      // User-Agent de navegador real: 'bot' en el UA hace que Cloudflare/WAFs bloqueen la petición.
      const r = await axios({
        method: 'GET',
        url,
        timeout: 12000,
        maxRedirects: 5,
        validateStatus: () => true,
        responseType: 'text',
        transformResponse: [x => x],
        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
          'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
          'Accept-Language': 'es-ES,es;q=0.9,en;q=0.8',
        },
      });
      const html = r.data || '';
      const text = html.replace(/<script[\s\S]*?<\/script>/gi, '')
                 .replace(/<style[\s\S]*?<\/style>/gi, '')
                 .replace(/<!--[\s\S]*?-->/g, '')
                 .replace(/<[^>]+>/g, ' ')
                 .replace(/\s+/g, ' ')
                 .trim()
                 .slice(0, 6000);
      // Texto muy corto suele indicar bloqueo o página vacía (SPA sin renderizar) — reintenta una vez
      if (text.length < 100 && attempt < retries) { await sleep(1500); continue; }
      return text || null;
    } catch (e) {
      if (attempt < retries) { await sleep(1500); continue; }
      return null;
    }
  }
  return null;
}

// Determinar qué niches necesitan análisis según closers activos, y cuántos closers
// comparten cada uno (a más demanda compartida, más análisis hacen falta ese niche)
const activeClosers = await sbGet(`closers?status=eq.active&select=id,selected_niches`);
const nicheCloserCounts = new Map();
for (const c of activeClosers) {
  (c.selected_niches || []).forEach(id => {
    nicheCloserCounts.set(id, (nicheCloserCounts.get(id) || 0) + 1);
  });
}
const neededNicheIds = new Set(nicheCloserCounts.keys());
console.log(`Niches activos: ${neededNicheIds.size}`);

const cutoff7d = new Date(Date.now() - 7 * 86400000).toISOString();
const prospects = await sbGet(
  `qualified_prospects?select=id,handle,platform_links,followers,detected_niche_id&order=qualified_at.desc&limit=150`
);
const existingAnalyses = await sbGet(
  `prospect_analyses?analyzed_at=gte.${cutoff7d}&select=prospect_id`
);
const analyzedIds = new Set(existingAnalyses.map(a => a.prospect_id));

// Hasta 5 por niche activo. Tope de seguridad para no descontrolar tiempo/coste de ejecución.
// Fallback: si el filtro de niche deja el pool vacío para algún niche concreto (caso límite,
// p.ej. un niche muy nuevo sin discovery aún), se ignora el filtro de niche solo en ese caso
// en vez de dejar el pipeline sin leads para nadie.
const unanalyzed = prospects.filter(p => !analyzedIds.has(p.id));
const nicheMatched = unanalyzed.filter(p => neededNicheIds.size === 0 || !p.detected_niche_id || neededNicheIds.has(p.detected_niche_id));
const pool = nicheMatched.length > 0 ? nicheMatched : unanalyzed;
if (nicheMatched.length === 0 && unanalyzed.length > 0) {
  console.log('⚠️ Ningún prospecto coincide con los niches de los closers — fallback sin filtro de niche');
}

// Tope por niche escala con cuántos closers lo comparten (más demanda → más análisis),
// con techo de 20/niche para no descontrolar coste de Claude/Apify si muchos closers
// se concentran en un solo niche.
const nicheCap = (nicheId) => Math.min(20, 5 * (nicheCloserCounts.get(nicheId) || 1));
const maxTotal = Math.min(150, Math.max(10, [...nicheCloserCounts.values()].reduce((sum, n) => sum + Math.min(20, 5 * n), 0)));
const toAnalyze = [];
const countPerNiche = {};
for (const p of pool) {
  const nk = p.detected_niche_id || 'unknown';
  countPerNiche[nk] = (countPerNiche[nk] || 0) + 1;
  const cap = nk === 'unknown' ? 5 : nicheCap(nk);
  if (countPerNiche[nk] > cap) continue;
  if (toAnalyze.length >= maxTotal) break;
  toAnalyze.push(p);
}
console.log(`Prospectos a analizar: ${toAnalyze.length} (pool: ${prospects.length}, por niche: ${JSON.stringify(countPerNiche)})`);

// ── Batch fetch reels (una sola llamada Apify para todos los perfiles) ────────
const reelsByHandle = {};
if (toAnalyze.length > 0) {
  console.log('Scrapeando reels en batch...');
  try {
    const urls = [...new Set(toAnalyze.map(p => `https://www.instagram.com/${p.handle}/`))];
    const posts = await apifyRunAndWait('apify~instagram-scraper', {
      directUrls: urls,
      resultsType: 'posts',
      resultsLimit: 5,
    }, 90000); // 90s max — suficiente para ≤5 perfiles
    for (const post of posts) {
      const h = post.ownerUsername;
      if (!h) continue;
      if (!reelsByHandle[h]) reelsByHandle[h] = [];
      if (reelsByHandle[h].length < 5) {
        reelsByHandle[h].push({
          caption: (post.caption || '').slice(0, 400),
          likes: post.likesCount || 0,
          views: post.videoViewCount || post.videoPlayCount || 0,
          type: post.type || 'Image',
          date: post.timestamp ? post.timestamp.split('T')[0] : null,
        });
      }
    }
    console.log(`Reels obtenidos: ${Object.keys(reelsByHandle).length} perfiles`);
  } catch (e) {
    console.log(`Reels batch falló (no bloqueante): ${e.message}`);
  }
}

const analyses = [];

for (const p of toAnalyze) {
  try {
  const landingUrl = p.platform_links?.landing;
  let landingText = '';
  if (landingUrl) {
    landingText = await fetchLandingText(landingUrl) || '';
    console.log(`  @${p.handle}: landing ${landingText ? 'OK' : 'no accesible'} (${landingUrl.slice(0, 60)})`);
  }

  // Meta Ads (requiere META_ADS_TOKEN — opcional, no bloquea)
  const ads = await queryMetaAds(p.handle);
  const adsText = ads.length > 0
    ? ads.map((ad, i) => {
        const body = (ad.ad_creative_bodies || []).join(' ') || '';
        const title = (ad.ad_creative_link_titles || []).join(' ') || '';
        return `Anuncio ${i+1}: ${title ? title + ' — ' : ''}${body}`.slice(0, 300);
      }).join('\n')
    : 'No disponibles (sin token Meta Ads o sin anuncios activos)';
  if (ads.length > 0) console.log(`  @${p.handle}: ${ads.length} anuncios Meta Ads encontrados`);

  // TikTok — busca handle en la bio/landing para intentar scraping
  const tiktokHandle = p.platform_links?.tiktok || null;
  let tiktokReels = [];
  if (tiktokHandle) {
    tiktokReels = await scrapeApifyTikTok(tiktokHandle);
    console.log(`  @${p.handle}: ${tiktokReels.length} vídeos TikTok`);
  }

  // Prompt §8.1 — análisis del embudo
  const funnelPrompt = `Eres un experto en embudos de venta de infoproductos en español.

IMPORTANTE: escribe tu análisis siempre en español neutro, sin modismos regionales (nunca uses
"vos", "tú" está bien). Esto aplica aunque la landing que analices use un dialecto distinto
(ej. argentino, mexicano) — no imites su tono, redacta el análisis en neutro. Si citas una frase
textual de la landing como evidencia, puedes citarla literal entre comillas, pero tu propio texto
de análisis debe ser siempre neutro.

Te paso el texto de la landing de un infoproductor. Analiza:
1. PROMESA principal (1 frase)
2. ESTRUCTURA: qué secciones tiene y en qué orden
3. PRUEBA SOCIAL: ¿hay? ¿dónde? ¿qué tipo?
4. CTA: ¿qué pide?
5. FRICCIONES: máximo 3 cosas que podrían bajar conversión
6. FORTALEZAS: máximo 2 cosas que están haciendo bien
7. ALTO_TICKET: ¿es una oferta de alto ticket? Considera alto ticket: mentoría personalizada,
   acompañamiento 1:1, consultoría premium, programas con aplicación o llamada de venta previa,
   o precio mencionado superior a 300-500€/$. Considera bajo ticket: cursos grabados masivos,
   ebooks, talleres con precio bajo o gratuito sin proceso de venta evidente. Responde "si", "no"
   o "desconocido" si la landing no da suficiente información para juzgarlo con confianza.

Devuelve SOLO el JSON con esos 7 campos, sin texto adicional ni bloques de código markdown. Empieza directamente con {.
El campo 7 debe tener forma: "alto_ticket": "si"|"no"|"desconocido", "alto_ticket_razon": "frase breve"

Handle: @${p.handle}
Followers: ${p.followers}
LANDING:
${landingText || '[No accesible — analiza solo con los datos del perfil de IG]'}`;

  const funnelAnalysis = await claude(funnelPrompt, 800);

  // Filtro de alto ticket: solo si Claude tuvo landing real para juzgar y dice claramente "no".
  // Sin landingText el juicio de Claude no es fiable, así que no se usa para descartar (cae a "desconocido").
  const groundedTicketJudgment = landingText ? String(funnelAnalysis?.alto_ticket || 'desconocido').toLowerCase() : 'desconocido';
  if (groundedTicketJudgment === 'no') {
    console.log(`  @${p.handle}: descartado — oferta de bajo ticket (${funnelAnalysis?.alto_ticket_razon || 'sin detalle'})`);
    continue;
  }

  // Reels del perfil (si disponibles)
  const reels = reelsByHandle[p.handle] || [];
  const reelsCaptions = reels.length > 0
    ? reels.map((r, i) => {
        const ago = r.date ? Math.floor((Date.now() - new Date(r.date)) / 86400000) + 'd atrás' : '';
        const engagement = r.views > 0 ? `${(r.views/1000).toFixed(1)}K views` : `${r.likes} likes`;
        return `Reel ${i+1} (${ago}, ${engagement}): ${r.caption || '(sin caption)'}`;
      }).join('\n')
    : 'No disponibles';

  // Combinar reels IG + TikTok
  const allReels = [...reels, ...tiktokReels].slice(0, 8);
  const allReelsCaptions = allReels.length > 0
    ? allReels.map((r, i) => {
        const platform = i < reels.length ? 'IG' : 'TT';
        const ago = r.date ? Math.floor((Date.now() - new Date(r.date)) / 86400000) + 'd atrás' : '';
        const engagement = r.views > 0 ? `${(r.views/1000).toFixed(1)}K views` : `${r.likes} likes`;
        return `[${platform}] Reel ${i+1} (${ago}, ${engagement}): ${r.caption || '(sin caption)'}`;
      }).join('\n')
    : 'No disponibles';

  // Prompt §8.3 — value_opportunities (incluye reels + ads)
  const valuePrompt = `Eres consultor de marketing para infoproductos en español. Tu trabajo es identificar
oportunidades concretas donde alguien podría aportar valor a este infoproductor en un primer contacto.

Tienes:
- Análisis del embudo: ${JSON.stringify(funnelAnalysis)}
- Handle: @${p.handle} | Followers: ${p.followers}
- REELS RECIENTES IG+TikTok (${allReels.length}):
${allReelsCaptions}
- ANUNCIOS ACTIVOS META (${ads.length}):
${adsText}

Identifica 2-4 OPORTUNIDADES DE VALOR. Prioriza las que se basen en algo concreto y específico observado
(una frase del reel, una fricción del embudo, un patrón en sus posts). Cada oportunidad debe:
- Ser específica (citar algo concreto, no "mejorar copy")
- Basarse en lo que acabas de ver en el material
- Ser accionable en horas/días
- NO ser un pitch de "contrátame": es un insight gratis que demuestra que entiendes su negocio

IMPORTANTE: este texto lo lee el closer, no el infoproductor — escribe "observation" y
"suggested_value" siempre en español neutro (sin "vos", sin modismos regionales), aunque el
infoproductor escriba en sus reels o posts con un dialecto distinto (ej. argentino, mexicano).
No imites su tono al redactar tu análisis. Si necesitas citar una frase textual suya como
evidencia, puedes hacerlo entre comillas, pero el resto de tu redacción debe ser neutro.

Devuelve SOLO el JSON array, sin texto adicional, sin bloques de código markdown. Empieza con [ y acaba con ].
Formato: { "area": "Embudo"|"Reels"|"Posicionamiento"|"Oferta"|"Anuncios", "observation": "...", "suggested_value": "..." }`;

  const valueOpportunities = await claude(valuePrompt, 800);

  // Clasificación launch vs evergreen — combina landing + reels
  // Captura la evidencia concreta (qué frase, en qué fuente) en vez de solo la etiqueta,
  // para que el closer vea por qué Soplo dice "Launch" y no sea una caja negra.
  const launchPattern = /masterclass|directo\s+gratis|webinar|reto\s+gratis|día\s+\d|plazas|esta\s+semana|lunes|martes|miércoles|jueves|viernes|\d+\s+de\s+\w+|últimas\s+plazas|abre\s+(matrí|inscri)|cierra\s+(matrí|inscri)/i;
  function findLaunchSignal(text, sourceLabel) {
    if (!text) return null;
    const m = text.match(launchPattern);
    if (!m) return null;
    const idx = m.index;
    const snippet = text.slice(Math.max(0, idx - 25), idx + m[0].length + 25).replace(/\s+/g, ' ').trim();
    return { source: sourceLabel, snippet };
  }
  const launchSignal = findLaunchSignal(landingText, 'landing')
    || findLaunchSignal(allReels.map(r => r.caption).join(' . '), 'reel')
    || findLaunchSignal(adsText, 'anuncio');
  const allText = landingText + ' ' + allReels.map(r => r.caption).join(' ') + ' ' + adsText;
  const hasLaunchSignals = !!launchSignal;

  const lastReelDays = allReels[0]?.date
    ? Math.floor((Date.now() - new Date(allReels[0].date)) / 86400000)
    : 999;

  // Actividad reciente
  const freshnessBonus = lastReelDays <= 3 ? 15 : lastReelDays <= 7 ? 10 : lastReelDays <= 14 ? 5 : 0;
  const stalePenalty = lastReelDays > 21 ? -10 : 0;

  // Lanzamiento activo — señal más valiosa
  const launchBonus = hasLaunchSignals ? 30 : 0;

  // Meta Ads activos — está invirtiendo para cerrar
  const adsBonus = ads.length >= 5 ? 30 : ads.length >= 3 ? 22 : ads.length >= 1 ? 12 : 0;

  // Señales de alto ticket — el juicio de Claude (con landing real) manda; si no hay landing
  // o Claude no tiene suficiente info ("desconocido"), se usa el respaldo de palabras clave + precio.
  const highTicketPattern = /mentor[íi]a|exclusivo|aplicar|reserva|plaza|mastermind|retiro|inmersi[oó]n|vip|1:1|acompa[ñn]amiento|consultor[íi]a|sesi[oó]n estrat[ée]gica|llamada estrat[ée]gica|diagn[oó]stico|cupos? limitados?|proceso de selecci[oó]n|agenda tu llamada|alto ticket|high ticket/i;
  const pricePattern = /(?:€|eur|\$|usd)\s?[1-9]\d{2,}(?:[.,]\d{3})*\b/i; // ej: 997€, $1.997, 500 eur
  const highTicketBonus = groundedTicketJudgment === 'si' ? 35
    : (highTicketPattern.test(allText) ? 15 : 0) + (pricePattern.test(allText) ? 10 : 0);

  // Followers: sweet spot 10K-50K (más accesible, tú eres de los primeros en contactar)
  const followerScore = Math.min(50, p.followers <= 50000
    ? (p.followers / 1000) * 2.5
    : 125 - ((p.followers - 50000) / 1000));

  const score = Math.min(100, Math.round(
    followerScore
    + (landingText ? 15 : 0)
    + freshnessBonus
    + stalePenalty
    + launchBonus
    + adsBonus
    + highTicketBonus
  ));

  // Evidencia de la clasificación embebida en funnel_summary — mismo patrón que alto_ticket_razon,
  // así el closer ve por qué se le dice "Launch" en vez de tener que confiar en una etiqueta a ciegas.
  funnelAnalysis.launch_evidence = launchSignal;

  analyses.push({
    prospect_id: p.id,
    funnel_summary: JSON.stringify(funnelAnalysis),
    vsl_transcript: null,
    creatives_analysis: ads.length > 0 ? ads : null,
    reels_summary: allReels.length > 0 ? allReels : null,
    value_opportunities: Array.isArray(valueOpportunities) ? valueOpportunities : [valueOpportunities],
    launch_date: null,
    classification: hasLaunchSignals ? 'launch' : 'evergreen',
    score,
    analyzed_at: new Date().toISOString(),
  });

  console.log(`  @${p.handle}: análisis OK — score ${analyses[analyses.length - 1].score}`);
  } catch (e) {
    // Aislado: un fallo en este prospecto (Claude, Apify, red) no debe perder los análisis ya generados
    console.log(`  @${p.handle}: análisis falló (no bloqueante): ${e.message}`);
  }
}

await sbUpsert('prospect_analyses', analyses, 'prospect_id');
console.log(`prospect_analyses guardados: ${analyses.length}`);

return [{ json: { analyzed: analyses.length } }];

// Stage 4: Matching + generación de mensajes con Claude
// Itera sobre todos los closers activos. Cada uno recibe sus propios candidatos.

const axios = require('axios');
async function fetch(url, opts) {
  opts = opts || {};
  const r = await axios({ method: opts.method || 'GET', url, headers: opts.headers || {}, data: opts.body, validateStatus: () => true, responseType: 'text', transformResponse: [x => x] });
  const text = r.data || '';
  return { ok: r.status >= 200 && r.status < 300, status: r.status, text: () => Promise.resolve(text), json: () => Promise.resolve(JSON.parse(text)) };
}

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet: ${await r.text()}`);
  return r.json();
}

async function sbInsert(table, rows) {
  if (!rows.length) return [];
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation' },
    body: JSON.stringify(rows),
  });
  if (!r.ok) throw new Error(`sbInsert ${table}: ${await r.text()}`);
  return r.json();
}

async function claude(system, user, maxTokens = 400, retries = 2) {
  let lastErr;
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const r = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': ANTHROPIC_KEY,
          'anthropic-version': '2023-06-01',
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-6',
          max_tokens: maxTokens,
          system,
          messages: [{ role: 'user', content: user }],
        }),
      });
      if (!r.ok) throw new Error(`Claude: ${await r.text()}`);
      const data = await r.json();
      return data.content[0].text.trim();
    } catch (e) {
      lastErr = e;
      if (attempt < retries) { console.log(`  Claude reintento ${attempt + 1}/${retries}: ${e.message}`); await new Promise(res => setTimeout(res, 2000 * (attempt + 1))); }
    }
  }
  throw lastErr;
}

// Veredicto de oportunidad — nunca se inventa un beneficio. Se basa solo en señales reales
// ya analizadas (anuncios, lanzamiento con evidencia, alto ticket confirmado por Claude, fricción
// real detectada). 'confirmado' = señal fuerte, 'dudoso' = señal débil (se entrega marcado),
// 'sin_beneficio' = ninguna señal real (no se entrega, no cuenta como una de las 5 plazas).
function computeOpportunityVerdict(a) {
  let fs = {};
  try { fs = a.funnel_summary ? JSON.parse(a.funnel_summary) : {}; } catch {}
  const adsCount = Array.isArray(a.creatives_analysis) ? a.creatives_analysis.length : 0;
  const altoTicket = String(fs.alto_ticket || 'desconocido').toLowerCase();
  const launchEvidence = fs.launch_evidence || null;
  const friccion = Array.isArray(fs.fricciones) ? fs.fricciones[0] : null;

  if (adsCount >= 3 || launchEvidence?.snippet || altoTicket === 'si') return 'confirmado';
  if (adsCount > 0 || friccion) return 'dudoso';
  return 'sin_beneficio';
}

// ── Todos los closers activos ─────────────────────────────────────────────────
const closers = await sbGet(`closers?status=eq.active&select=id,email,tone_profile,selected_niches`);
console.log(`Closers activos: ${closers.length}`);
if (!closers.length) return [{ json: { messages: 0, note: 'sin closers activos' } }];

// Fairness: cuando varios closers comparten un niche con poca oferta, sin esto los primeros
// de la lista (por antigüedad de registro) siempre "ganarían" y los últimos se quedarían
// sistemáticamente sin leads. Se prioriza a quien menos leads ha recibido en los últimos 7 días.
const cutoff7d = new Date(Date.now() - 7 * 86400000).toISOString();
const recentAssignments = await sbGet(`lead_assignments?assigned_at=gte.${cutoff7d}&select=closer_id`);
const assignmentCounts = new Map();
for (const a of recentAssignments) {
  assignmentCounts.set(a.closer_id, (assignmentCounts.get(a.closer_id) || 0) + 1);
}
closers.sort((a, b) => (assignmentCounts.get(a.id) || 0) - (assignmentCounts.get(b.id) || 0));

// ── Pool de análisis compartido (se consulta una vez para todos) ──────────────
// Límite ampliado: con varios niches activos, el pool necesita cubrir 5 análisis por niche
const analyses = await sbGet(
  `prospect_analyses?select=id,prospect_id,value_opportunities,classification,score,funnel_summary,creatives_analysis`
  + `&score=gte.0&order=score.desc&limit=100`
);

const now = new Date();
const expires = new Date(now.getTime() + 24 * 3600 * 1000);
const cutoff30d = new Date(Date.now() - 30 * 86400000).toISOString();

// Exclusividad global: prospects ya asignados a cualquier closer en 30 días
// Se actualiza durante la ejecución para que los closers procesados primero no solapeen con los siguientes
const allAssigned = await sbGet(
  `lead_assignments?assigned_at=gte.${cutoff30d}&select=prospect_id`
);
const globallyAssigned = new Set(allAssigned.map(a => a.prospect_id));

// Categoría de cada niche — permite el fallback "misma categoría" cuando el niche exacto
// elegido por el closer no tiene oferta ese día (ej. eligió crypto-web3 → cae en Finanzas)
const allNichesMeta = await sbGet(`niches?select=id,category`);
const categoryByNicheId = new Map(allNichesMeta.map(n => [n.id, n.category]));

let totalMessages = 0;
const allPreviews = [];

for (const closer of closers) {
  try {
  const tp = closer.tone_profile || {};
  const ss = tp.style_summary || {};
  const transcripts = tp.transcripts || [];
  const regionPref = tp.region_preference || 'both';
  const closerNiches = closer.selected_niches || [];
  const closerCategories = new Set(closerNiches.map(id => categoryByNicheId.get(id)).filter(Boolean));

  // Candidatos válidos: exclusividad global + región. El routing por niche se resuelve
  // en 3 niveles de prioridad para garantizar las 5 plazas sin inventar oferta que no existe:
  //   Nivel 1: niche exacto elegido por el closer
  //   Nivel 2: misma categoría que alguno de sus niches (ej. eligió crypto-web3 → cae en Finanzas)
  //   Nivel 3: cualquier niche (última red de seguridad, solo si 1 y 2 no llenan las 5 plazas)
  const seenHandles = new Set();
  const candidatesByTier = { 1: [], 2: [], 3: [] };
  for (const a of analyses) {
    const [qp] = await sbGet(`qualified_prospects?id=eq.${a.prospect_id}&select=handle,platform_links,detected_niche_id`);
    if (!qp || globallyAssigned.has(a.prospect_id)) continue;

    // Región: la región opuesta a la elegida NUNCA se muestra, sin excepción (ej. closer
    // pidió España, jamás recibe LATAM). "unknown" (sin señales claras en el perfil) se
    // permite solo como último recurso — nunca tiene prioridad sobre un match exacto.
    const prospectRegion = qp.platform_links?.region || 'unknown';
    let regionRank = 2; // 2 = coincide o sin preferencia de región, 1 = unknown (último recurso)
    if (regionPref !== 'both') {
      const oppositeRegion = regionPref === 'spain' ? 'latam' : 'spain';
      if (prospectRegion === oppositeRegion) continue; // exclusión dura, sin excepción
      regionRank = prospectRegion === regionPref ? 2 : 1;
    }

    if (seenHandles.has(qp.handle)) continue;
    seenHandles.add(qp.handle);

    // Sin beneficio real detectado: no se entrega, no ocupa una de las 5 plazas del día.
    // Se filtra aquí (antes de elegir los 5 finales) para no reducir la cuota del closer.
    const verdict = computeOpportunityVerdict(a);
    if (verdict === 'sin_beneficio') continue;

    const prospectNicheId = qp.detected_niche_id || null;
    const prospectCategory = prospectNicheId ? categoryByNicheId.get(prospectNicheId) : null;
    let tier;
    if (closerNiches.length === 0 || !prospectNicheId) tier = 1;
    else if (closerNiches.includes(prospectNicheId)) tier = 1;
    else if (prospectCategory && closerCategories.has(prospectCategory)) tier = 2;
    else tier = 3;

    candidatesByTier[tier].push({ ...a, _nicheId: prospectNicheId || 'unknown', _regionRank: regionRank, _verdict: verdict });
  }

  // Región exacta primero, luego anuncios activos (mejor score primero)
  const adsFirst = (a, b) => {
    if (a._regionRank !== b._regionRank) return b._regionRank - a._regionRank;
    const aAds = Array.isArray(a.creatives_analysis) && a.creatives_analysis.length > 0 ? 1 : 0;
    const bAds = Array.isArray(b.creatives_analysis) && b.creatives_analysis.length > 0 ? 1 : 0;
    return bAds - aAds;
  };
  candidatesByTier[1].sort(adsFirst);
  candidatesByTier[2].sort(adsFirst);
  candidatesByTier[3].sort(adsFirst);

  // Reparto equilibrado dentro de un nivel: cada niche con candidatos aporta al menos 1 lead
  // antes de que el niche con más volumen se quede con todos los slots.
  function balancedPick(list, slotsNeeded) {
    const byNiche = new Map();
    for (const c of list) {
      if (!byNiche.has(c._nicheId)) byNiche.set(c._nicheId, []);
      byNiche.get(c._nicheId).push(c);
    }
    const groups = [...byNiche.values()];
    const picked = [];
    let round = 0;
    while (picked.length < slotsNeeded && groups.some(g => g.length > round)) {
      for (const group of groups) {
        if (picked.length >= slotsNeeded) break;
        if (group.length > round) picked.push(group[round]);
      }
      round++;
    }
    return picked;
  }

  let top = balancedPick(candidatesByTier[1], 5);
  let usedTier2 = false, usedTier3 = false;
  if (top.length < 5) { usedTier2 = candidatesByTier[2].length > 0; top = top.concat(balancedPick(candidatesByTier[2], 5 - top.length)); }
  if (top.length < 5) { usedTier3 = candidatesByTier[3].length > 0; top = top.concat(balancedPick(candidatesByTier[3], 5 - top.length)); }

  const tierNote = usedTier3 ? ' (con fallback a cualquier niche)' : usedTier2 ? ' (con fallback a misma categoría)' : '';
  console.log(`[${closer.email}] Candidatos: niche=${candidatesByTier[1].length} categoría=${candidatesByTier[2].length} otros=${candidatesByTier[3].length} → seleccionados: ${top.length}${tierNote}`);
  if (!top.length) continue;

  // System prompt con el tono de este closer
  const systemPrompt = `Eres este closer escribiendo un mensaje de Instagram a un infoproductor.

PERFIL DEL CLOSER (cómo habla):
Variante de español: ${ss.spanish_variant || 'Español peninsular'}
Registro: ${ss.register || 'Cercano, conversacional'}
Energía: ${ss.energy || 'medio-alto'}
Frases características: ${(ss.characteristic_phrases || []).join(', ')}
Muletillas: ${(ss.filler_words || []).join(', ')}
Aperturas típicas: ${(ss.typical_openers || []).join(', ')}
Formalidad: ${ss.formality_level || 2}/5

EJEMPLOS DE CÓMO HABLA ESTE CLOSER:
${transcripts.slice(0, 3).map(t => t.text?.slice(0, 400)).join('\n---\n')}`;

  for (const analysis of top) {
    try {
    const [qp] = await sbGet(`qualified_prospects?id=eq.${analysis.prospect_id}&select=handle,platform_links,followers`);
    if (!qp) continue;

    const opportunities = Array.isArray(analysis.value_opportunities) ? analysis.value_opportunities : [];
    let vo = opportunities.find(o => o && typeof o.observation === 'string' && o.observation.trim());

    // Fallback: construir vo desde funnel_summary si no hay value_opportunities
    if (!vo) {
      try {
        const fs = analysis.funnel_summary ? JSON.parse(analysis.funnel_summary) : {};
        const friction = Array.isArray(fs.fricciones) ? fs.fricciones[0] : null;
        const strength = Array.isArray(fs.fortalezas) ? fs.fortalezas[0] : null;
        if (friction || fs.promesa) {
          vo = {
            area: 'Embudo',
            observation: friction || fs.promesa || 'Tiene landing activa',
            suggested_value: strength ? `Reforzar ${strength.toLowerCase()}` : 'Mejorar conversión del embudo',
          };
        }
      } catch {}
    }

    if (!vo) {
      console.log(`  @${qp?.handle || '?'}: sin datos suficientes para mensaje — omitido`);
      continue;
    }

    const sourceLabel = vo.area === 'Reels' ? 'reel' : vo.area === 'Embudo' ? 'landing' : vo.area?.toLowerCase() || 'perfil';

    const userPrompt = `INFOPRODUCTOR: @${qp.handle}

LO QUE HAS OBSERVADO (no lo reveles del todo — úsalo para crear curiosidad):
Área: ${vo.area} (${sourceLabel})
Observación: ${vo.observation}
Valor que aportarías: ${vo.suggested_value}

ESTRUCTURA OBLIGATORIA DEL MENSAJE (3 partes):
1. TRIGGER: menciona dónde lo viste de forma específica. Ej: "Estaba mirando tu landing", "He visto tu reel de ayer", "Estaba leyendo tu página de X".
2. TEASER: di que viste algo que podría [beneficio vago relacionado con el valor]. NO expliques el qué todavía. Crea curiosidad.
3. SOFT CLOSE: "Si te interesa te cuento" / "Si quieres te comento" / "Me dices y te explico". NUNCA una pregunta abierta, NUNCA un CTA de venta.

EJEMPLOS DE REFERENCIA de esta estructura (adapta el TONO al closer, no copies el contenido):
Ejemplo A: "Estaba mirando tu linktr.ee y he visto algo que podría ahorrarte tiempo y filtraría mejor a los que quieren trabajar contigo. Si te interesa, me dices y te explico."
Ejemplo B: "He estado leyendo la estrategia que ofreces gratuita y al final en agendar llamada, he visto un pequeño detalle en el calendario que podría mejorar mucho el cierre cuando te agenden llamada. Si quieres te comento."

INSTRUCCIONES CRÍTICAS:
- Escribe en el tono exacto del closer (sus muletillas, su ritmo, sus aperturas).
- MÁXIMO 40 palabras. Menos es más.
- NO expliques el insight en el mensaje. Solo insinúalo.
- PROHIBIDO: adulación de cualquier tipo, preguntas abiertas al final, "te llevo siguiendo".
- Empieza por el trigger, no por el @handle ni por "Hola".

Devuelve SOLO el texto del mensaje. Sin comillas, sin explicaciones.`;

    const messageText = await claude(systemPrompt, userPrompt, 200);
    if (!messageText || messageText.trim().length < 10) {
      console.log(`  @${qp.handle}: Claude devolvió mensaje vacío — omitido`);
      continue;
    }
    console.log(`  @${qp.handle}: mensaje generado (${messageText.trim().split(/\s+/).length} palabras)`);

    const [assignment] = await sbInsert('lead_assignments', [{
      prospect_id: analysis.prospect_id,
      closer_id: closer.id,
      assigned_at: now.toISOString(),
      expires_at: expires.toISOString(),
      status: 'pending',
    }]);

    if (assignment?.id) {
      await sbInsert('generated_messages', [{
        assignment_id: assignment.id,
        message_text: messageText,
        value_point: vo.observation,
      }]);
      globallyAssigned.add(analysis.prospect_id); // evita que este prospect vaya a otro closer en esta misma ejecución
      allPreviews.push({ closer: closer.email, handle: qp.handle, message: messageText.slice(0, 80) + '...' });
      totalMessages++;
    }
    } catch (e) {
      // Aislado: un fallo generando este mensaje no debe impedir los demás leads del mismo closer
      console.log(`  [${closer.email}] candidato falló (no bloqueante): ${e.message}`);
    }
  }

  console.log(`[${closer.email}] Mensajes generados: ${top.length}`);
  } catch (e) {
    // Aislado: un fallo con este closer no debe impedir que los demás closers reciban sus leads
    console.log(`[${closer.email}] Procesamiento falló (no bloqueante): ${e.message}`);
  }
}

console.log(`Total mensajes generados: ${totalMessages}`);
return [{ json: { messages: totalMessages, preview: allPreviews } }];
